def require_owner_acknowledgement(
    action_item: ActionItem,
    acknowledged_by: str,
    acknowledged_at: datetime,
) -> ActionItem:
    if acknowledged_by != action_item.owner:
        raise ValueError(
            f"Acknowledgement must come from the owner ({action_item.owner}), "
            f"not {acknowledged_by}"
        )
    action_item.state = ActionItemState.IN_PROGRESS
    return action_item

def escalate_unacknowledged(
    action_item: ActionItem,
    days_since_creation: int,
    em_owner: str,
) -> ActionItem:
    # If owner has not acknowledged within 3 business days, EM becomes co-owner
    if days_since_creation >= 3 and action_item.state == ActionItemState.OPEN:
        action_item.escalation_owner = em_owner
    return action_item

def close_action_item(
    action_item: ActionItem,
    closed_by: str,
    evidence_url: str,
    closed_at: datetime,
) -> ActionItem:
    if closed_by == action_item.owner:
        raise PermissionError(
            "Action items must be closed by a reviewer, not the owner. "
            f"Owner: {action_item.owner}"
        )
    if not evidence_url:
        raise ValueError("Closing an action item requires an evidence URL (PR, alert link, etc.)")
    action_item.state = ActionItemState.CLOSED
    action_item.closed_at = closed_at
    return action_item

from datetime import date, timedelta

def compute_escalation_state(
    action_item: ActionItem,
    category_slas: dict[str, int],
    hard_escalation_days: dict[str, int],
    as_of: date | None = None,
) -> dict:
    check = as_of or date.today()
    if action_item.state == ActionItemState.CLOSED:
        return {"escalation_level": "none", "days_overdue": 0}
    days_overdue = action_item.days_overdue(check)
    hard_threshold = hard_escalation_days.get(action_item.category.value, 999)
    if days_overdue == 0:
        level = "none"
    elif days_overdue <= 3:
        level = "owner_notified"
    elif days_overdue <= 7:
        level = "em_notified"
    elif days_overdue <= hard_threshold:
        level = "em_escalation"
    else:
        level = "director_escalation"
    return {
        "escalation_level": level,
        "days_overdue": days_overdue,
        "hard_escalation_in_days": max(0, hard_threshold - days_overdue),
    }

def build_team_dashboard(
    team_id: str,
    action_items: list[ActionItem],
    as_of: date | None = None,
) -> dict:
    check = as_of or date.today()
    team_items = [ai for ai in action_items if get_owner_team(ai.owner) == team_id]
    total = len(team_items)
    closed = sum(1 for ai in team_items if ai.state == ActionItemState.CLOSED)
    overdue = sum(1 for ai in team_items if ai.is_overdue(check))
    blocked = sum(1 for ai in team_items if ai.state == ActionItemState.BLOCKED)
    by_owner = {}
    for ai in team_items:
        by_owner.setdefault(ai.owner, {"open": 0, "overdue": 0, "blocked": 0, "closed": 0})
        if ai.state == ActionItemState.CLOSED:
            by_owner[ai.owner]["closed"] += 1
        elif ai.is_overdue(check):
            by_owner[ai.owner]["overdue"] += 1
        elif ai.state == ActionItemState.BLOCKED:
            by_owner[ai.owner]["blocked"] += 1
        else:
            by_owner[ai.owner]["open"] += 1
    return {
        "team_id": team_id,
        "total": total,
        "closed": closed,
        "closure_rate": closed / total if total else 0,
        "overdue": overdue,
        "blocked": blocked,
        "by_owner": by_owner,
    }
